SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY A.R_TIME DESC, A.EMPID
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

SELECT COUNT(*)
  FROM AR_MAC_RECORDS_HTSV_EAT
 WHERE EMPID     = #{empId,    jdbcType=VARCHAR}
   AND R_TIME = TO_DATE(#{cardTime, jdbcType=VARCHAR}, 'YYYY/MM/DD HH24:MI')
   AND EAT_NAME = #{doorName, jdbcType=VARCHAR}
